// Cross-validation tests for NSGA-II/III sorting, hypervolume, HSSP,
// box decomposition, and Pareto front identification.
// Python baseline generated by tests/generate_nsga_sorting_baseline.py.

use std::collections::HashMap;
use optuna_rs::multi_objective::{
    crowding_distance, dominates, fast_non_dominated_sort,
    hypervolume, hypervolume_2d, is_pareto_front,
    solve_hssp, get_non_dominated_box_bounds,
};
use optuna_rs::samplers::nsgaiii::{generate_reference_points, perpendicular_distance};
use optuna_rs::study::StudyDirection;
use optuna_rs::trial::{FrozenTrial, TrialState};

const TOL: f64 = 1e-10;
const TOL_RELAX: f64 = 1e-6;

fn load_baseline() -> serde_json::Value {
    let data = include_str!("nsga_sorting_baseline.json");
    serde_json::from_str(data).expect("Failed to parse nsga sorting baseline JSON")
}

fn get_f64(val: &serde_json::Value, key: &str) -> f64 {
    match &val[key] {
        serde_json::Value::Number(n) => n.as_f64().unwrap(),
        serde_json::Value::String(s) if s == "Infinity" => f64::INFINITY,
        serde_json::Value::String(s) if s == "-Infinity" => f64::NEG_INFINITY,
        serde_json::Value::String(s) if s == "NaN" => f64::NAN,
        v => panic!("Unexpected value for {key}: {v:?}"),
    }
}

fn get_f64_vec(val: &serde_json::Value, key: &str) -> Vec<f64> {
    val[key]
        .as_array()
        .unwrap()
        .iter()
        .map(|v| match v {
            serde_json::Value::Number(n) => n.as_f64().unwrap(),
            serde_json::Value::String(s) if s == "Infinity" => f64::INFINITY,
            serde_json::Value::String(s) if s == "-Infinity" => f64::NEG_INFINITY,
            serde_json::Value::String(s) if s == "NaN" => f64::NAN,
            other => panic!("Unexpected value in {key}: {other:?}"),
        })
        .collect()
}

fn get_int_vec(val: &serde_json::Value, key: &str) -> Vec<i64> {
    val[key]
        .as_array()
        .unwrap()
        .iter()
        .map(|v| v.as_i64().unwrap())
        .collect()
}

fn get_bool_vec(val: &serde_json::Value, key: &str) -> Vec<bool> {
    val[key]
        .as_array()
        .unwrap()
        .iter()
        .map(|v| match v {
            serde_json::Value::Bool(b) => *b,
            serde_json::Value::Number(n) => n.as_i64().unwrap_or(0) != 0,
            other => panic!("Unexpected value in {key}: {other:?}"),
        })
        .collect()
}

fn assert_close(got: f64, expected: f64, tol: f64, label: &str) {
    if expected.is_infinite() {
        assert!(
            got.is_infinite() && got.signum() == expected.signum(),
            "{label}: expected {expected}, got {got}"
        );
    } else if expected.is_nan() {
        assert!(got.is_nan(), "{label}: expected NaN, got {got}");
    } else {
        let diff = (got - expected).abs();
        let denom = expected.abs().max(1.0);
        assert!(
            diff / denom < tol,
            "{label}: expected {expected}, got {got}, rel_err = {:.2e}",
            diff / denom
        );
    }
}

fn make_trial(number: i64, values: Vec<f64>) -> FrozenTrial {
    FrozenTrial::new(
        number,
        TrialState::Complete,
        None,
        Some(values),
        Some(chrono::Utc::now()),
        Some(chrono::Utc::now()),
        HashMap::new(),
        HashMap::new(),
        HashMap::new(),
        HashMap::new(),
        HashMap::new(),
        number,
    )
    .unwrap()
}

