#[test]
fn cv_sort_hv_4d() {
    let b = load_baseline();
    let expected = get_f64(&b, "hv_4d");
    let points = vec![
        vec![1.0, 2.0, 3.0, 4.0],
        vec![2.0, 1.0, 4.0, 3.0],
        vec![3.0, 3.0, 1.0, 2.0],
        vec![4.0, 4.0, 2.0, 1.0],
    ];
    let reference = vec![6.0, 6.0, 6.0, 6.0];
    let hv = hypervolume(&points, &reference);
    assert_close(hv, expected, TOL, "hv_4d");
}

