//  4. Box decomposition
// ═══════════════════════════════════════════════════════════════════════════

#[test]
fn cv_sort_box_decomp_2d() {
    let b = load_baseline();
    let expected_lower: Vec<Vec<f64>> = b["box_2d_lower"]
        .as_array().unwrap()
        .iter()
        .map(|row| row.as_array().unwrap().iter()
            .map(|v| match v {
                serde_json::Value::Number(n) => n.as_f64().unwrap(),
                serde_json::Value::String(s) if s == "-Infinity" => f64::NEG_INFINITY,
                serde_json::Value::String(s) if s == "Infinity" => f64::INFINITY,
                other => panic!("Unexpected: {other:?}"),
            }).collect()
        ).collect();
    let expected_upper: Vec<Vec<f64>> = b["box_2d_upper"]
        .as_array().unwrap()
        .iter()
        .map(|row| row.as_array().unwrap().iter()
            .map(|v| match v {
                serde_json::Value::Number(n) => n.as_f64().unwrap(),
                serde_json::Value::String(s) if s == "-Infinity" => f64::NEG_INFINITY,
                serde_json::Value::String(s) if s == "Infinity" => f64::INFINITY,
                other => panic!("Unexpected: {other:?}"),
            }).collect()
        ).collect();

    let points = vec![
        vec![1.0, 4.0],
        vec![2.0, 2.0],
        vec![4.0, 1.0],
    ];
    let ref_point = vec![6.0, 6.0];

    let (lower, upper) = get_non_dominated_box_bounds(&points, &ref_point);

    assert_eq!(lower.len(), expected_lower.len(), "box_2d lower count mismatch");
    assert_eq!(upper.len(), expected_upper.len(), "box_2d upper count mismatch");

    for (i, (got_l, exp_l)) in lower.iter().zip(expected_lower.iter()).enumerate() {
        for (j, (&g, &e)) in got_l.iter().zip(exp_l.iter()).enumerate() {
            assert_close(g, e, TOL, &format!("box_2d_lower[{i}][{j}]"));
        }
    }
    for (i, (got_u, exp_u)) in upper.iter().zip(expected_upper.iter()).enumerate() {
        for (j, (&g, &e)) in got_u.iter().zip(exp_u.iter()).enumerate() {
            assert_close(g, e, TOL, &format!("box_2d_upper[{i}][{j}]"));
        }
    }
}

