// ═══════════════════════════════════════════════════════════════════════════
//  5. Non-dominated sorting: mixed directions
// ═══════════════════════════════════════════════════════════════════════════

#[test]
fn cv_sort_nds_mixed_direction() {
    let b = load_baseline();
    let expected = get_int_vec(&b, "nds_ranks_mixed_dir");

    // obj0: Minimize, obj1: Maximize
    // Original values (NOT negated — Rust handles direction internally)
    let trials: Vec<FrozenTrial> = vec![
        make_trial(0, vec![1.0, 5.0]),
        make_trial(1, vec![2.0, 4.0]),
        make_trial(2, vec![3.0, 3.0]),
        make_trial(3, vec![4.0, 2.0]),
        make_trial(4, vec![5.0, 1.0]),
        make_trial(5, vec![2.5, 2.5]),
        make_trial(6, vec![1.5, 4.5]),
        make_trial(7, vec![4.5, 1.5]),
        make_trial(8, vec![3.0, 3.0]),
        make_trial(9, vec![6.0, 6.0]),
    ];
    let trial_refs: Vec<&FrozenTrial> = trials.iter().collect();
    let dirs = vec![StudyDirection::Minimize, StudyDirection::Maximize];
    let fronts = fast_non_dominated_sort(&trial_refs, &dirs);

    let mut ranks = vec![0i64; trials.len()];
    for (rank, front) in fronts.iter().enumerate() {
        for &idx in front {
            ranks[idx] = rank as i64;
        }
    }
    assert_eq!(ranks, expected, "nds_ranks_mixed_dir mismatch");
}

