#[test]
fn cv_sort_perpendicular_distance() {
    let b = load_baseline();
    let expected = get_f64_vec(&b, "perpendicular_distances");

    let cases: Vec<(Vec<f64>, Vec<f64>)> = vec![
        (vec![1.0, 0.0], vec![1.0, 0.0]),
        (vec![1.0, 1.0], vec![1.0, 0.0]),
        (vec![0.5, 0.5], vec![1.0, 1.0]),
        (vec![1.0, 2.0, 3.0], vec![1.0, 1.0, 1.0]),
        (vec![3.0, 0.0, 0.0], vec![1.0, 0.0, 0.0]),
        (vec![1.0, 1.0, 1.0], vec![0.0, 0.0, 1.0]),
    ];

    for (i, ((pt, dir), &exp)) in cases.iter().zip(expected.iter()).enumerate() {
        let got = perpendicular_distance(pt, dir);
        assert_close(got, exp, TOL, &format!("perp_dist[{i}]"));
    }
}

