#[test]
fn cv_sort_das_dennis_counts() {
    let b = load_baseline();
    let expected_counts = get_int_vec(&b, "dd_counts");

    let cases = [(2, 4), (3, 3), (4, 3), (5, 2)];
    for (i, &(n_obj, div)) in cases.iter().enumerate() {
        let pts = generate_reference_points(n_obj, div);
        assert_eq!(
            pts.len() as i64, expected_counts[i],
            "Das-Dennis({n_obj}, {div}) count mismatch"
        );
    }
}

#[test]
fn cv_sort_das_dennis_points_2d_4div() {
    let b = load_baseline();
    let expected: Vec<Vec<f64>> = b["dd_points"]["dd_2d_4div"]
        .as_array().unwrap()
        .iter()
        .map(|row| row.as_array().unwrap().iter()
            .map(|v| v.as_f64().unwrap()).collect::<Vec<f64>>())
        .collect();

    let mut got = generate_reference_points(2, 4);
    got.sort_by(|a: &Vec<f64>, b: &Vec<f64>| {
        for i in 0..a.len() {
            match a[i].partial_cmp(&b[i]) {
                Some(std::cmp::Ordering::Equal) => continue,
                Some(ord) => return ord,
                None => return std::cmp::Ordering::Equal,
            }
        }
        std::cmp::Ordering::Equal
    });

    assert_eq!(got.len(), expected.len(), "dd_2d_4div point count");
    for (i, (g, e)) in got.iter().zip(expected.iter()).enumerate() {
        for (j, (gv, ev)) in g.iter().zip(e.iter()).enumerate() {
            assert_close(*gv, *ev, TOL, &format!("dd_2d_4div[{i}][{j}]"));
        }
    }
}

