// ═══════════════════════════════════════════════════════════════════════════
// 11. Dominance properties
// ═══════════════════════════════════════════════════════════════════════════

#[test]
fn cv_sort_dominates_nan_handling() {
    let dirs = vec![StudyDirection::Minimize, StudyDirection::Minimize];
    // NaN in partial_cmp returns None → treated as "not worse" (skip),
    // so [NaN, 1.0] vs [2.0, 2.0]: dim0 NaN→skip, dim1 1<2→dominated_in_any=true → true!
    // This matches Rust's partial_cmp semantics. Python avoids NaN in values.
    // Key property: identical NaN values should NOT dominate.
    assert!(!dominates(&[f64::NAN, f64::NAN], &[f64::NAN, f64::NAN], &dirs));
    // Two NaN dimensions cannot establish dominated_in_any
    assert!(!dominates(&[f64::NAN, f64::NAN], &[1.0, 1.0], &dirs));
    // Self-dominance is always false
    assert!(!dominates(&[1.0, 1.0], &[1.0, 1.0], &dirs));
}

#[test]
fn cv_sort_crowding_distance_preserves_order() {
    // Crowding distance should be independent of input order
    let trials1: Vec<FrozenTrial> = vec![
        make_trial(0, vec![1.0, 5.0]),
        make_trial(1, vec![3.0, 3.0]),
        make_trial(2, vec![5.0, 1.0]),
    ];
    let trials2: Vec<FrozenTrial> = vec![
        make_trial(0, vec![5.0, 1.0]),
        make_trial(1, vec![1.0, 5.0]),
        make_trial(2, vec![3.0, 3.0]),
    ];

    let refs1: Vec<&FrozenTrial> = trials1.iter().collect();
    let refs2: Vec<&FrozenTrial> = trials2.iter().collect();
    let dirs = vec![StudyDirection::Minimize, StudyDirection::Minimize];

    let cd1 = crowding_distance(&refs1, &dirs);
    let cd2 = crowding_distance(&refs2, &dirs);

    // cd1[0] should equal cd2[1] (both are [1, 5])
    assert_close(cd1[0], cd2[1], TOL, "cd order [1,5]");
    // cd1[1] should equal cd2[2] (both are [3, 3])
    assert_close(cd1[1], cd2[2], TOL, "cd order [3,3]");
    // cd1[2] should equal cd2[0] (both are [5, 1])
    assert_close(cd1[2], cd2[0], TOL, "cd order [5,1]");
}

// ═══════════════════════════════════════════════════════════════════════════
// 12. End-to-end: NDS → Crowding distance → Elite selection
// ═══════════════════════════════════════════════════════════════════════════

#[test]
fn cv_sort_nds_then_crowding() {
    // Verify the pipeline: NDS assigns ranks, then crowding distance
    // breaks ties within the same front
    let trials: Vec<FrozenTrial> = vec![
        make_trial(0, vec![1.0, 4.0]),   // front 0
        make_trial(1, vec![2.0, 2.0]),   // front 0
        make_trial(2, vec![4.0, 1.0]),   // front 0
        make_trial(3, vec![3.0, 3.0]),   // front 1
        make_trial(4, vec![5.0, 5.0]),   // front 2
    ];
    let trial_refs: Vec<&FrozenTrial> = trials.iter().collect();
    let dirs = vec![StudyDirection::Minimize, StudyDirection::Minimize];

    // Step 1: NDS
    let fronts = fast_non_dominated_sort(&trial_refs, &dirs);
    assert_eq!(fronts.len(), 3, "Expected 3 fronts");
    assert_eq!(fronts[0].len(), 3, "Front 0 should have 3 trials");
    assert_eq!(fronts[1].len(), 1, "Front 1 should have 1 trial");
    assert_eq!(fronts[2].len(), 1, "Front 2 should have 1 trial");

    // Step 2: Crowding distance on front 0
    let front0_trials: Vec<&FrozenTrial> = fronts[0].iter().map(|&i| &trials[i]).collect();
    let cd = crowding_distance(&front0_trials, &dirs);

    // Boundary solutions should have infinite crowding distance
    // The sorted order for obj0 is: trial0(1.0), trial1(2.0), trial2(4.0)
    // Boundary = first and last in each dimension → trial0 and trial2
    // With sentinel padding, boundaries always get contributions from inf gaps
    // In a 3-point front, the middle point gets finite CD
    assert!(cd.iter().any(|&c| c.is_finite()), "At least one non-boundary in front 0");
}

