#[test]
fn cv_sort_hv_empty() {
    let points: Vec<Vec<f64>> = vec![];
    let reference = vec![5.0, 5.0];
    assert_eq!(hypervolume(&points, &reference), 0.0, "HV of empty set");
}

#[test]
fn cv_sort_hv_dominated_point() {
    // Point beyond reference should contribute nothing
    let points = vec![
        vec![1.0, 1.0],
        vec![10.0, 10.0],  // beyond reference
    ];
    let reference = vec![5.0, 5.0];
    let hv = hypervolume(&points, &reference);
    // Should equal HV of just the first point
    let hv_single = hypervolume(&vec![vec![1.0, 1.0]], &reference);
    assert_close(hv, hv_single, TOL, "HV dominated point");
}

#[test]
fn cv_sort_hv_2d_via_generic() {
    // Verify generic hypervolume matches hypervolume_2d for 2D case
    let points = vec![
        vec![1.0, 4.0],
        vec![2.0, 2.0],
        vec![4.0, 1.0],
    ];
    let reference = vec![6.0, 6.0];
    let hv_generic = hypervolume(&points, &reference);

    let pts_2d: Vec<[f64; 2]> = points.iter().map(|p| [p[0], p[1]]).collect();
    let hv_2d = hypervolume_2d(&pts_2d, [6.0, 6.0]);

    assert_close(hv_generic, hv_2d, TOL, "HV 2D generic vs specialized");
}
